import React from 'react';
import * as FiIcons from 'react-icons/fi'; // He sarvat safe aahe

const ServiceCard = ({ iconName, title, desc, color }) => {
  const Icon = FiIcons[iconName] || FiIcons.FiPackage; 
  return (
    <div style={{
      flex: '1', minWidth: '280px', margin: '15px', padding: '30px',
      backgroundColor: 'rgba(255, 255, 255, 0.92)', borderRadius: '20px', textAlign: 'center',
      boxShadow: '0 10px 30px rgba(0,0,0,0.1)', borderTop: `6px solid ${color}`,
      backdropFilter: 'blur(10px)', transition: '0.3s'
    }}>
      <div style={{ fontSize: '3.5rem', color: color, marginBottom: '15px' }}>
        <Icon />
      </div>
      <h5 style={{ fontWeight: 'bold', color: '#333', textTransform: 'uppercase' }}>{title}</h5>
      <p style={{ color: '#666', fontSize: '0.85rem' }}>{desc}</p>
      <button style={{ backgroundColor: color, color: 'white', border: 'none', padding: '10px 25px', borderRadius: '25px', fontWeight: 'bold', cursor: 'pointer' }}>Select Service</button>
    </div>
  );
};

const Home = () => {
  return (
    <div style={{ padding: '60px 20px' }}>
      <div style={{ textAlign: 'center', marginBottom: '50px' }}>
        <h1 style={{ fontSize: '3.5rem', fontWeight: '900', color: '#1a1a1a', textShadow: '2px 2px 10px rgba(255,255,255,0.8)' }}>
          Apni Manzil <span style={{ color: '#0056b3' }}>Logistics</span>
        </h1>
        <p style={{ fontSize: '1.2rem', color: '#0056b3', fontWeight: '700', background: 'white', display: 'inline-block', padding: '8px 25px', borderRadius: '40px', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}>
          Smart Aggregator for MSMEs & Partners
        </p>
      </div>
      <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', maxWidth: '1200px', margin: '0 auto' }}>
        <ServiceCard iconName="FiPackage" title="Courier Services" desc="Express Domestic & Local Delivery" color="#2ecc71" />
        <ServiceCard iconName="FiTruck" title="Transport" desc="Heavy Haulage & Trucking Partners" color="#f1c40f" />
        <ServiceCard iconName="FiBriefcase" title="Business MSME" desc="Bulk 3PL & Supply Chain Solutions" color="#3498db" />
        <ServiceCard iconName="FiGlobe" title="International" desc="Air & Sea Freight Cargo Services" color="#9b59b6" />
      </div>
    </div>
  );
};

export default Home;
